parameters.jsCode:
const item = $input.item.json;
const rawString = item.text || item.output || item.content || "";

let jsonData = { category: "未分類", content: "無內容", metadata: {}, question_type: "multiple_choice", rubric: "" };
try {
  const cleanString = rawString.replace(/```json/g, "").replace(/```/g, "").trim();
  if (cleanString) jsonData = JSON.parse(cleanString);
} catch (e) { console.log("解析失敗"); }

let metaObj = (typeof jsonData.metadata === 'string') ? JSON.parse(jsonData.metadata) : (jsonData.metadata || {});

return {
  json: {
    category: jsonData.category || "一般",
    content: jsonData.content,
    metadata: metaObj,
    question_type: jsonData.question_type || "multiple_choice",
    rubric: jsonData.rubric || null
  }
};

