// 取得所有題目資料
let questions = items.map(item => item.json);

// 1. 先照 ID 由大到小排 (確保我們抓到的是「最新」的題目)
questions.sort((a, b) => b.id - a.id);

// 2. 擷取最新的前 10 筆
questions = questions.slice(0, 10);

// 3. 🔥 把這 10 筆的順序反轉過來 (變成畫面上顯示 ID 由小到大)
questions.reverse();

// 標題
let msg = "📂 **題庫總覽 (最近 10 筆)**\n------------------\n";

// 迴圈串接每一題
questions.forEach(q => {
    // 讀取題目 (相容新舊格式)
    const content = q.content || q.question_text || "無內容";
    const topic = q.metadata?.topic || q.category || "未分類";

    // 限制 40 字，且只有超過時才加 "..."
    const limit = 40; 
    const preview = content.length > limit ? content.substring(0, limit) + "..." : content;

    msg += `🆔 **${q.id}** [${topic}]\n`;
    msg += `${preview}\n\n`; 
});

msg += "💡 輸入 /list [ID] 可查看詳情";

return [{ json: { text: msg } }];

