// 1. 從 Webhook 源頭抓取資料 (最穩定)
const event = $('Webhook').first().json.body.events[0];
const replyToken = event.replyToken;
const userId = event.source.userId;
const sourceType = event.source.type; // user (私訊) 或 group (群組)

// 2. 準備回覆文字 (恢復原本的引導說明)
// 因為我們移除了 LLM，所以這裡直接寫死引導文字
const agentText = '你好，請提供姓名和學號範例:(灰太郎 11123456)';

// 3. 判斷邏輯 (處理 Tag 問題)
if (sourceType === 'user') {
  // ==========================================
  // 🅰️ 私訊模式 (單純回覆文字)
