  return {
    replyToken,
    messages: [
      {
        type: 'text',
        text: `👋 ${agentText}` 
      }
    ]
  };

} else {
  // ==========================================
  // 🅱️ 群組模式 (使用 Mention Tag)
  // ==========================================
  return {
    replyToken,
    messages: [
      {
        type: 'textV2',
        text: `{user} ${agentText}`,
        substitution: {
          user: {
            type: 'mention',
            mentionee: {
              type: 'user',
              userId: userId, 
            },
          },
        },
      },
    ],
  };
}

// 取得前 10 名資料
const rows = items.map(item => item.json);

if (rows.length === 0) {
  return [{ json: { text: "🏆 目前還沒有人答對過題目喔！快來搶頭香！" } }];
}

// 標題區
let msg = "🏆 **榮耀排行榜 (Top 10)**\n====================\n";

rows.forEach((row, index) => {
  let rankDisplay = "";

  // 🔥 設計前三名的特殊樣式
  if (index === 0) {
    // 第一名：加皇冠 + 火焰 + 冠軍稱號
    rankDisplay = `🥇 [冠軍] ${row.display_name}\n      └── ⚔️ 答對 ${row.score} 題 🔥`;
  } else if (index === 1) {
    // 第二名
    rankDisplay = `🥈 [亞軍] ${row.display_name} : ${row.score} 題`;
  } else if (index === 2) {
    // 第三名
    rankDisplay = `🥉 [季軍] ${row.display_name} : ${row.score} 題`;
  } else {
    // 第四名以後：簡單數字排列
    rankDisplay = `No.${index + 1}  ${row.display_name} : ${row.score} 題`;
  }

  msg += `${rankDisplay}\n`;
});

msg += "\n💪 各位同學繼續加油！";

return [{ json: { text: msg } }];

// 取得 Supabase 查到的所有資料
const allStudents = items.map(item => item.json);

// 分組：答對的放一邊，答錯的放一邊
const correctList = allStudents.filter(s => s.is_correct === true);
const wrongList = allStudents.filter(s => s.is_correct === false);

// 定義一個小函式來整理名單 (格式：1. 王小明 (12345) [選A])
const formatList = (list) => {
    if (list.length === 0) return "   (無)";
    return list.map((s, i) => `${i + 1}. ${s.display_name} (${s.student_id}) [選${s.selected_option}]`).join('\n');
};

// 組合最終訊息
const message = `📊 第 ${allStudents[0]?.question_id || '?'} 題完整統計

✅ 答對人數：${correctList.length} 人
----------------
${formatList(correctList)}

❌ 答錯人數：${wrongList.length} 人
----------------
${formatList(wrongList)}`;

// 輸出
return [{
    json: {
        reply_text: message
    }
}];

// 1. 安全地取得使用者的訊息與 UserID
const event = $('Webhook').first().json.body.events[0];

// 🌟 關鍵修正：加上 ?. 保護！防止非文字事件（如按鈕點擊、加好友）導致崩潰
const text = event?.message?.text || "";
const userId = event?.source?.userId || "";

// 2. 正規表達式解析註冊指令
const regex = /^\s*(?:註冊)?\s*([^\d\s]+)[\s:：]*(\d+)/i;
const match = text.match(regex);

// 3. 判斷是否抓取成功
if (match && text !== "") { // 確保真的有文字才進行註冊判斷
  return {
    valid: true,
    user_id: userId,
    name: match[1],      // 抓到的名字
    student_id: match[2] // 抓到的學號
  };
} else {
  // 格式不對或根本不是文字訊息 (例如只打了 "註冊" 但沒給資料，或是點擊了按鈕)
  return {
    valid: false
  };
}

// 1. 抓取輸入資料 (題目)
const q = $input.first().json;
const parseData = $("解析測驗指令").first().json; 

// 🌟 關鍵修正：原本找「查詢群組ID」，現在改找我們剛建好的「防呆與分流中樞」
const finalGroupId = $("防呆與分流中樞").first().json.final_group_id;

// 3. 準備參數
const gameMode = parseData.game_mode || "normal";
const duration = parseData.duration || 3;
const opts = q.metadata?.options || ["(A)", "(B)", "(C)", "(D)"];

// 4. 根據模式決定標題與提示
let modeTag = "📝 隨堂測驗"; 
let promptText = "";

if (gameMode.startsWith("limit_")) {
    const limitN = gameMode.split("_")[1];
    modeTag = `🔥 搶答挑戰 (前 ${limitN} 名) 🔥`;
    promptText = `⚡️ 注意：只有「前 ${limitN} 名」答對者能獲得積分！\n(限時 ${duration} 分鐘)\n`;
} else {
    modeTag = "📝 隨堂測驗 📝";
    promptText = `✨ 考驗實力的時刻到了，請認真作答！\n(限時 ${duration} 分鐘)\n`;
}

// 5. 組合最終卡片文案
const questionBlock = q.content ? `[題目]\n${q.content}\n\n` : "";
const fullContent = `${promptText}=======================\n\n${questionBlock}[選項]\n(A) ${opts[0]}\n(B) ${opts[1]}\n(C) ${opts[2]}\n(D) ${opts[3]}\n\n👇 請點擊下方按鈕作答！ 👇`;

// 6. 隨機產生主題顏色
const colors = ["#1DB446", "#007AFF", "#9C27B0", "#E91E63", "#009688"];
const finalColor = gameMode.startsWith("limit_") ? "#E60012" : colors[Math.floor(Math.random() * colors.length)];

// 7. 輸出
return {
  text: fullContent,
  qid: q.id, 
  group_id: finalGroupId,
  theme_color: finalColor,
  mode_tag: modeTag,
  raw_command: parseData.original_cmd
};

// 1. 強制鎖定當前點擊按鈕的學生
const currentUserId = $('Webhook').first().json.body.events[0].source.userId;

// 2. 抓取正確的遊戲模式與群組
const gameMode = $('找id').first().json.game_mode || "normal"; 
const groupId = $('找id').first().json.group_id;

// 3. 取得「查詢答對名單」的所有資料 (將多筆紀錄打包成一個陣列)
const rawRecords = $input.all().map(item => item.json);

// 4. 依照寫入時間 (created_at) 由舊到新排序
const correctRecords = rawRecords.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));

let score = 0;
let rank = 0;
let actionType = "normal"; 
let needClose = false;

// 5. 找出「當前學生」在排行榜中的真實名次 (Index + 1)
const rankIndex = correctRecords.findIndex(r => r.user_id === currentUserId);
rank = (rankIndex !== -1) ? (rankIndex + 1) : (correctRecords.length + 1); 

// 6. 根據遊戲模式給分
if (gameMode.startsWith("limit_")) {
  const limitN = parseInt(gameMode.split("_")[1]); 

  if (rank <= limitN) {
    score = 5; // 🌟 限量搶答的分數
    actionType = "limit_success";
    // 剛好滿額，觸發關門
    if (rank === limitN) {
      actionType = "limit_full";
      needClose = true;
    }
  } else {
    score = 0; 
    actionType = "limit_late";
  }

} else {
  // 🌟 一般模式計分機制更新
  if (rank === 1) {
    score = 100; // 🥇 第一名
  } else if (rank <= 5) {
    score = 90;  // 🚀 第二 ~ 五名
  } else if (rank <= 10) {
    score = 80;  // ⭐ 第六 ~ 十名
  } else {
    score = 60;  // 🐢 第十一名以後
  }

  actionType = "speed"; 
}

// 7. 🔥 終極防護：強制只輸出「一筆」資料，阻止 n8n 迴圈亂跑
return [{
  json: {
    score: score,
    rank: rank,
    actionType: actionType,
    needClose: needClose,
    group_id: groupId,
    userId: currentUserId 
  }
}];

// 1. 取得解析好的資料
// (這裡相容剛剛的防呆修改，優先抓 my_groups，沒有才用原本的方式)
const groups = $json.my_groups || $input.all().map(item => item.json); 
const parseData = $("解析測驗指令").first().json; 

const { qid, duration, limit, target_group_name, original_cmd } = parseData;

// 🔥 關鍵新增：判斷來源是否為群組，若是則在開頭準備好「@ 」
const sourceType = $('Webhook').first().json.body.events[0].source.type;
const prefix = (sourceType === 'group' || sourceType === 'room') ? "@ " : "";

// 輔助函式：產生 1-5 的數字按鈕
const createNumberButtons = (prefixCommand) => {
  return [1, 2, 3, 4, 5].map(num => ({
    "type": "button",
    "style": "secondary",
    "height": "sm",
    "action": { 
      "type": "message", 
      "label": `${num}`, 
      // 👇 這裡加上 prefix 變數
      "text": `${prefix}${prefixCommand} ${num}` 
    },
    "margin": "xs"
  }));
};

// --- 階段 1：如果缺「時間」 ---
if (duration === null) {
  return {
    flex_json: {
      "type": "bubble",
      "header": { "type": "box", "layout": "vertical", "contents": [{ "type": "text", "text": "⏳ 請選擇測驗限時 (分鐘)", "weight": "bold", "color": "#FFFFFF", "align": "center" }], "backgroundColor": "#464a4d" },
      "body": { "type": "box", "layout": "vertical", "contents": [{ "type": "box", "layout": "horizontal", "contents": createNumberButtons(`${original_cmd} ${qid}`) }] }
    }
  };
}

// --- 階段 2：如果是 /openlimit 且缺「人數」 ---
if (original_cmd === '/openlimit' && limit === null) {
  return {
    flex_json: {
      "type": "bubble",
      "header": { "type": "box", "layout": "vertical", "contents": [{ "type": "text", "text": "👥 請選擇搶答名額 (人數)", "weight": "bold", "color": "#FFFFFF", "align": "center" }], "backgroundColor": "#E60012" },
      "body": { "type": "box", "layout": "vertical", "contents": [{ "type": "box", "layout": "horizontal", "contents": createNumberButtons(`${original_cmd} ${qid} ${duration}`) }] }
    }
  };
}

// --- 階段 3：參數齊全，缺「班級」 ---
if (target_group_name === null) {
  const baseCmd = (original_cmd === '/openlimit') 
    ? `${original_cmd} ${qid} ${duration} ${limit}` 
    : `${original_cmd} ${qid} ${duration}`;

  const buttons = groups.map(g => {
    const groupName = g.group_name || (g.groups && g.groups.group_name) || "未命名群組";
    return {
      "type": "button",
      "style": "primary",
      "height": "sm",
      "action": { 
        "type": "message", 
        "label": groupName, 
        // 👇 這裡加上 prefix 變數
        "text": `${prefix}${baseCmd} ${groupName}` 
      },
      "margin": "sm"
    };
  });

  return {
    flex_json: {
      "type": "bubble",
      "header": { "type": "box", "layout": "vertical", "contents": [{ "type": "text", "text": "🏫 最後一步：選擇發送班級", "weight": "bold", "color": "#FFFFFF", "align": "center" }], "backgroundColor": (original_cmd === '/openlimit') ? "#E60012" : "#4CAF50" },
      "body": { "type": "box", "layout": "vertical", "contents": buttons }
    }
  };
}

// 如果參數都齊全了，就不輸出卡片（後續流程會發送測驗題目）
return { skip: true };

// 1. 取得使用者的班級列表，並【過濾掉無效的空資料】
// 🔥 修正點：加了 .filter 確保只有真的有 group_id 的資料才被留下來
const myGroups = $input.all()
  .map(item => item.json)
  .filter(g => g.group_id); 

// 2. 製作班級按鈕
const groupButtons = myGroups.map(g => {
  // 抓取名稱，如果沒 Join 到就用 ID 代替
  const name = g.groups ? g.groups.group_name : (g.group_name || "未命名班級");

  return {
    "type": "button",
    "style": "secondary",
    "action": {
      "type": "message",
      "label": name,
      "text": `/me_query group ${name}` 
    }
  };
});

// 3. 加入「生涯總戰績」按鈕
const totalButton = {
  "type": "button",
  "style": "primary",
  "color": "#1DB446",
  "action": {
    "type": "message",
    "label": "🌏 生涯總戰績",
    "text": "/me_query total"
  }
};

// 4. 組合選單內容 (改用動態陣列 push 的方式)
const contents = [
  {
    "type": "text",
    "text": "📊 請選擇查詢範圍",
    "weight": "bold",
    "size": "lg",
    "align": "center"
  },
  {
    "type": "separator",
    "margin": "md"
  },
  // 這裡一定會有「總戰績」按鈕
  {
    "type": "box",
    "layout": "vertical",
    "margin": "md",
    "contents": [ totalButton ]
  }
];

// 5. 🔥 關鍵修正：只有當真的有班級時，才加入下方區塊
if (groupButtons.length > 0) {
  // 加入分隔標題
  contents.push({
    "type": "text",
    "text": "個別班級戰績：",
    "size": "xs",
    "color": "#aaaaaa",
    "margin": "lg"
  });

  // 加入班級按鈕列表
  contents.push({
    "type": "box",
    "layout": "vertical",
    "spacing": "sm",
    "margin": "sm",
    "contents": groupButtons
  });
}

// 6. 包裝成 Flex Message
const flexPayload = {
  "type": "bubble",
  "body": {
    "type": "box",
    "layout": "vertical",
    "contents": contents
  }
};

return { flex_json: flexPayload };

// 1. 取得資料
const items = $input.all().map(item => item.json);

// 2. 👻 處理「沒有戰績」的情況 (防呆)
// 如果陣列是空的，或是第一筆資料是空的物件
if (items.length === 0 || Object.keys(items[0]).length === 0) {
  const replyToken = $('Webhook').first().json.body.events[0].replyToken;
  return {
    flex_json: {
      "type": "bubble",
      "body": {
        "type": "box",
        "layout": "vertical",
        "contents": [
          {
            "type": "text",
            "text": "尚無答題紀錄",
            "weight": "bold",
            "color": "#ff5555",
