parameters.jsCode:
// 1. 抓取文字內容
const currentText = $json.body?.events?.[0]?.message?.text;
const webhookNode = $('Webhook').first();
const backupText = webhookNode.json.body.events?.[0]?.message?.text || "";
const text = currentText || backupText;

// 判斷是否為純數字的輔助函式
const isNum = (val) => val && /^\d+$/.test(val);

// 2. 正則表達式：只抓取 /openlimit 或 /open
const regex = /\/(openlimit|open)\s+(\d+)(?:\s+(\S+))?(?:\s+(\S+))?(?:\s+(.+))?/;
const match = text.match(regex);

const currentGroupId = $json.body?.events?.[0]?.source?.groupId || webhookNode.json.body.events?.[0]?.source?.groupId || null;

if (match) {
  const cmd = match[1]; // openlimit 或 open
  const qid = match[2];
  let duration = null;
  let limit = null;
  let targetGroup = null;

  if (cmd === 'openlimit') {
    // /openlimit 邏輯
    if (isNum(match[3])) {
      duration = parseInt(match[3]);
      if (isNum(match[4])) {
        limit = parseInt(match[4]);
        targetGroup = match[5] ? match[5].trim() : null;
      } else {
        // 有 duration，沒 limit，剩下的都是群組名稱
        targetGroup = [match[4], match[5]].filter(Boolean).join(' ').trim() || null;
      }
    } else {
      // 缺 duration 和 limit，剩下的都是群組名稱
      targetGroup = [match[3], match[4], match[5]].filter(Boolean).join(' ').trim() || null;
    }
  } else {
    // /open 邏輯：組合可能被空白切斷的群組名稱
    if (isNum(match[3])) {
      duration = parseInt(match[3]);
      // 將 match[4] 與 match[5] 組合，避免包含空白的群組名稱被截斷
      targetGroup = [match[4], match[5]].filter(Boolean).join(' ').trim() || null;
    } else {
      // 若連 duration 都沒填，則剩下的全是群組名稱
      targetGroup = [match[3], match[4], match[5]].filter(Boolean).join(' ').trim() || null;
    }
  }

  return {
    valid: true,
    game_mode: (cmd === 'open') ? "normal" : (limit ? `limit_${limit}` : "limit_pending"),
    qid,
    duration,
    limit,
    target_group_name: targetGroup,
    current_group_id: currentGroupId,
    original_cmd: `/${cmd}` // 儲存原始指令名稱 (/openlimit)
  };
}

return { valid: false };

