parameters.jsCode:
// 1. 取得老師名下的所有班級 (來自上一個 Supabase 節點)
const myGroups = $input.all().map(item => item.json);

// 2. 取得一開始解析好的指令資料
const cmd = $('解析測驗指令').first().json;

let status = "ready";
let error_msg = "";
let finalGroupId = null;

// === 防呆第一關：檢查必要參數 ===
if (cmd.duration === null) {
    status = "need_param"; // 缺時間
} else if (cmd.original_cmd === '/openlimit' && cmd.limit === null) {
    status = "need_param"; // 缺限量名額
} 

// === 防呆第二關：環境與權限判斷 ===
else if (cmd.current_group_id) {
    // 【情境 A：在群組內直接下指令】
    // 檢查：老師名下的班級，有沒有包含這個群組 ID？
    const matchedGroup = myGroups.find(g => g.group_id === cmd.current_group_id);
    if (matchedGroup) {
        finalGroupId = matchedGroup.group_id;
    } else {
        status = "error";
        error_msg = "⛔ 防呆阻擋：您尚未將此群組註冊為您的班級，或沒有權限在此開啟測驗。";
    }
} else {
    // 【情境 B：在單人私訊下指令】
    if (cmd.target_group_name) {
        // 檢查：老師輸入的班級名稱，存不存在於他的名單中？
        const matchedGroup = myGroups.find(g => 
            g.group_name === cmd.target_group_name || 
            (g.groups && g.groups.group_name === cmd.target_group_name)
        );
        if (matchedGroup) {
            finalGroupId = matchedGroup.group_id || matchedGroup.groups.group_id;
        } else {
            status = "error";
            error_msg = `⛔ 防呆阻擋：找不到名為「${cmd.target_group_name}」的班級，請確認名稱是否打錯。`;
        }
    } else {
        status = "need_param"; // 沒打班級名稱，跳去產生選單卡片
    }
}

// 3. 輸出結果與打包資料
return {
    json: {
        status: status,
        error_msg: error_msg,
        final_group_id: finalGroupId,
        my_groups: myGroups, // 把群組清單打包往下傳，給產生卡片的節點用
        ...cmd
    }
};
